-- ============================================================
-- TABLA: comisarias_pnp
-- Prontuario telefónico - Regiones: Tumbes, La Libertad,
-- Lambayeque, Amazonas, Piura
-- ============================================================

CREATE TABLE IF NOT EXISTS comisarias_pnp (
    id BIGSERIAL PRIMARY KEY,
    region TEXT NOT NULL,
    comando_superior TEXT NOT NULL,
    nombre TEXT NOT NULL,
    tipo TEXT,
    categoria TEXT,
    direccion TEXT,
    distrito TEXT,
    provincia TEXT,
    departamento TEXT,
    telefono TEXT,
    created_at TIMESTAMPTZ DEFAULT NOW()
);

-- Índices útiles
CREATE INDEX IF NOT EXISTS idx_comisarias_region ON comisarias_pnp(region);
CREATE INDEX IF NOT EXISTS idx_comisarias_departamento ON comisarias_pnp(departamento);
CREATE INDEX IF NOT EXISTS idx_comisarias_nombre ON comisarias_pnp(nombre);

